@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam class {
  BackgroundColor #F2F2F2
  BorderColor #333333
  HeaderBackgroundColor #F2F2F2
  AttributeBackgroundColor #F2F2F2
}

class "Proyecto" as Proyecto <<C>> {
  Nombre: "1 Texto"
  Fecha de inicio: 1 Tiempo
  Fecha de fin: 0..1 Tiempo
}

class "Miembros del Equipo" as MiembrosDelEquipo <<C>> {
  Nombre: 1 Texto
  Apellidos: 1 Texto
  Rol: 0..* Texto
}

class "Lugar de Actuacion" as LugarDeActuacion <<C>> {
  Nombre: 0..* Texto
  Coordenada X: 1 Número
  Coordenada Y: 1 Número
}

Proyecto -[hidden]- MiembrosDelEquipo
Proyecto -[hidden]- LugarDeActuacion
MiembrosDelEquipo -[hidden]- LugarDeActuacion
@enduml
